\hspace*{-0.75in}
    \includegraphics[width=1.2\linewidth]{scatter_WC_WN3O3.pdf}
    \caption{Left panel: Luminosity vs our measured $v_\perp$ for the WC and WN3/O3 stars for which luminosity data is available in the literature from \citet{Aadland2022a, Aadland2022b} and \citet{Neugent2017}, respectively, along with the WN4/O4 star studied by \citet{Massey2024}.  Right panel: $V$ magnitude vs $v_\perp$ for all of the WC stars and WN3/O3 stars in our Gaia samples. The blue stars show the single WC stars that appear in both panels. Arrows indicate lower limits for objects with no Gaia velocity measurements; these objects are likely still bound within clusters (see text). }
    \label{fig:magvsvel}
\end{figure*}

